30     static std::shared_ptr<ModelPart> MakePlane(float width, float height, PMaterial mat = MaterialDefaults::ColorMaterial::Create(Color::RED), Math3D::Vec3 normal = Math3D::Vec3(0,1,0)){
31         std::shared_ptr<ModelPart> part;
32         auto factory = ModelPartFactory::Create(mat);
33         int v1, v2, v3, v4;
34         factory
35             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,0.0f,-1.0f)).UV(0,0).Norm(normal), &v1)
36             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,0.0f,-1.0f)).UV(1,0).Norm(normal), &v2)
37             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,0.0f, 1.0f)).UV(1,1).Norm(normal), &v3)
38             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,0.0f, 1.0f)).UV(0,1).Norm(normal), &v4)
39             .defineFace(v1,v4,v3,v2);
40 
41         part = factory.assemble();
42         part->localTransform.setScale(Math3D::Vec3(width,1.0f,height));
43         return part;
44     }
