54     static std::shared_ptr<ModelPart> MakeBox(float width, float height, float depth,PMaterial mat = MaterialDefaults::ColorMaterial::Create(Color::RED)){
55         auto factory = ModelPartFactory::Create(mat);
56         int v0, v1, v2, v3, v4, v5, v6, v7, v8, v9, v10, v11, v12, v13, v14, v15, v16, v17, v18, v19, v20, v21, v22, v23;
57 
58         factory
59             // Front face (Z = 1.0, Normal = 0, 0, 1)
60             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f, -1.0f,  1.0f)).UV(0,0).Norm(Math3D::Vec3(0,0,1)), &v0)
61             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f, -1.0f,  1.0f)).UV(1,0).Norm(Math3D::Vec3(0,0,1)), &v1)
62             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,  1.0f,  1.0f)).UV(1,1).Norm(Math3D::Vec3(0,0,1)), &v2)
63             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,  1.0f,  1.0f)).UV(0,1).Norm(Math3D::Vec3(0,0,1)), &v3)
64 
65             // Back face (Z = -1.0, Normal = 0, 0, -1)
66             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f, -1.0f, -1.0f)).UV(0,0).Norm(Math3D::Vec3(0,0,-1)), &v4)
67             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f, -1.0f, -1.0f)).UV(1,0).Norm(Math3D::Vec3(0,0,-1)), &v5)
68             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,  1.0f, -1.0f)).UV(1,1).Norm(Math3D::Vec3(0,0,-1)), &v6)
69             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,  1.0f, -1.0f)).UV(0,1).Norm(Math3D::Vec3(0,0,-1)), &v7)
70 
71             // Top face (Y = 1.0, Normal = 0, 1, 0)
72             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,  1.0f, -1.0f)).UV(0,0).Norm(Math3D::Vec3(0,1,0)), &v8)
73             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,  1.0f, -1.0f)).UV(1,0).Norm(Math3D::Vec3(0,1,0)), &v9)
74             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,  1.0f,  1.0f)).UV(1,1).Norm(Math3D::Vec3(0,1,0)), &v10)
75             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,  1.0f,  1.0f)).UV(0,1).Norm(Math3D::Vec3(0,1,0)), &v11)
76 
77             // Bottom face (Y = -1.0, Normal = 0, -1, 0)
78             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f, -1.0f, -1.0f)).UV(0,1).Norm(Math3D::Vec3(0,-1,0)), &v12)
79             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f, -1.0f, -1.0f)).UV(1,1).Norm(Math3D::Vec3(0,-1,0)), &v13)
80             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f, -1.0f,  1.0f)).UV(1,0).Norm(Math3D::Vec3(0,-1,0)), &v14)
81             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f, -1.0f,  1.0f)).UV(0,0).Norm(Math3D::Vec3(0,-1,0)), &v15)
82 
83             // Right face (X = 1.0, Normal = 1, 0, 0)
84             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f, -1.0f, -1.0f)).UV(0,0).Norm(Math3D::Vec3(1,0,0)), &v16)
85             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f, -1.0f,  1.0f)).UV(1,0).Norm(Math3D::Vec3(1,0,0)), &v17)
86             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,  1.0f,  1.0f)).UV(1,1).Norm(Math3D::Vec3(1,0,0)), &v18)
87             .addVertex(Vertex::Build(Math3D::Vec3( 1.0f,  1.0f, -1.0f)).UV(0,1).Norm(Math3D::Vec3(1,0,0)), &v19)
88 
89             // Left face (X = -1.0, Normal = -1, 0, 0)
90             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f, -1.0f,  1.0f)).UV(0,0).Norm(Math3D::Vec3(-1,0,0)), &v20)
91             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f, -1.0f, -1.0f)).UV(1,0).Norm(Math3D::Vec3(-1,0,0)), &v21)
92             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,  1.0f, -1.0f)).UV(1,1).Norm(Math3D::Vec3(-1,0,0)), &v22)
93             .addVertex(Vertex::Build(Math3D::Vec3(-1.0f,  1.0f,  1.0f)).UV(0,1).Norm(Math3D::Vec3(-1,0,0)), &v23)
94 
95             // Define the 6 faces
96             .defineFace(v0, v1, v2, v3)   // Front
97             .defineFace(v4, v5, v6, v7)   // Back
98             .defineFace(v8, v11, v10, v9) // Top
99             .defineFace(v12, v13, v14, v15) // Bottom
100             .defineFace(v16, v19, v18, v17) // Right
101             .defineFace(v20, v23, v22, v21); // Left
102 
103         auto part = factory.assemble();
104         part->localTransform.setScale(Math3D::Vec3(width, height, depth));
105         return part;
106     }
