116     static std::shared_ptr<ModelPart> MakeCirclePlane(
117         float radius, 
118         int segments = 32, 
119         PMaterial material = MaterialDefaults::ColorMaterial::Create(Color::RED), 
120         Math3D::Vec3 normal = Math3D::Vec3(0,1,0)
121     ){
122         auto factory = ModelPartFactory::Create(material);
123 
124         int centerIndex;
125         factory.addVertex(Vertex::Build(Math3D::Vec3(0,0,0)).UV(0.5f,0.5f).Norm(normal), &centerIndex);
126 
127         int firstEdgeIndex = -1, lastEdgeIndex = -1;
128         for(int i = 0; i <= segments; i++){
129             float theta = (float)i / (float)segments * 2.0f * (float) Math3D::PI;
130 
131             float x = Math3D::Cos(theta);
132             float z = Math3D::Sin(theta);
133 
134             int currentIndex;
135             float u = x * 0.5f + 0.5f;
136             float v = z * 0.5f + 0.5f;
137 
138             factory.addVertex(Vertex::Build(Math3D::Vec3(x,0.0f,z)).UV(u,v).Norm(normal), &currentIndex);
139 
140             if(i == 0) firstEdgeIndex = currentIndex;
141 
142             if(i > 0){
143                 factory.defineFace(centerIndex, currentIndex, lastEdgeIndex);
144             }
145             lastEdgeIndex = currentIndex;
146         }
147 
148         auto part = factory.assemble();
149 
150         part->localTransform.setScale(Math3D::Vec3(radius, 1.0f, radius));
151 
152         return part;
153     }
