163     static std::shared_ptr<ModelPart> MakeSphere(
164         float radius = 1.0f,
165         int slices = 32,
166         int stacks = 18,
167         PMaterial material = MaterialDefaults::ColorMaterial::Create(Color::WHITE)
168     ){
169         slices = Math3D::Max(slices, 8);
170         stacks = Math3D::Max(stacks, 6);
171         if(radius <= Math3D::EPSILON){
172             radius = 1.0f;
173         }
174         if(!material){
175             material = MaterialDefaults::ColorMaterial::Create(Color::WHITE);
176         }
177 
178         auto factory = ModelPartFactory::Create(material);
179         std::vector<int> indices(static_cast<size_t>((stacks + 1) * (slices + 1)), -1);
180 
181         for(int stack = 0; stack <= stacks; ++stack){
182             float v = (float)stack / (float)stacks;
183             float phi = v * (float)Math3D::PI;
184             float y = std::cos(phi);
185             float ringRadius = std::sin(phi);
186 
187             for(int slice = 0; slice <= slices; ++slice){
188                 float u = (float)slice / (float)slices;
189                 float theta = u * (float)Math3D::PI * 2.0f;
190                 float x = ringRadius * std::cos(theta);
191                 float z = ringRadius * std::sin(theta);
192 
193                 Math3D::Vec3 normal(x, y, z);
194                 if(normal.length() <= Math3D::EPSILON){
195                     normal = Math3D::Vec3(0.0f, 1.0f, 0.0f);
196                 }else{
197                     normal = normal.normalize();
198                 }
199 
200                 Vertex vertex = Vertex::Build(Math3D::Vec3(normal.x * radius, normal.y * radius, normal.z * radius))
201                                     .Norm(normal)
202                                     .UV(u, 1.0f - v);
203                 int outIndex = -1;
204                 factory.addVertex(vertex, &outIndex);
205                 indices[(size_t)stack * (size_t)(slices + 1) + (size_t)slice] = outIndex;
206             }
207         }
208 
209         for(int stack = 0; stack < stacks; ++stack){
210             for(int slice = 0; slice < slices; ++slice){
211                 int i00 = indices[(size_t)stack * (size_t)(slices + 1) + (size_t)slice];
212                 int i01 = indices[(size_t)stack * (size_t)(slices + 1) + (size_t)(slice + 1)];
213                 int i10 = indices[(size_t)(stack + 1) * (size_t)(slices + 1) + (size_t)slice];
214                 int i11 = indices[(size_t)(stack + 1) * (size_t)(slices + 1) + (size_t)(slice + 1)];
215 
216                 if(stack == 0){
217                     factory.defineFace(i00, i11, i10);
218                 }else if(stack == (stacks - 1)){
219                     factory.defineFace(i00, i01, i10);
220                 }else{
221                     factory.defineFace(i00, i11, i10);
222                     factory.defineFace(i00, i01, i11);
223                 }
224             }
225         }
226 
227         return factory.assemble();
228     }
229 };
